  <div class="notice-right">
    <div class="text-wrap">
      <h1 class="title" data-full="Opps ...!"></h1>
      <p class="subtitle">You don't have access to this topic yet</p>
      <p class="body">Please register first to join this program. Thank you.</p>
      <div class="actions">
        <button class="btn primary" id="signup" onclick="window.location.href='/dashboard/student/'">Register Now</button>
        <button class="btn ghost" id="back" onclick="window.location.href='/dashboard/'">Back</button>
      </div>
    </div>
  </div>
</section>

<style>

/* layout */
.notice-row{
  display:flex;
  gap:28px;
  align-items:center;
  padding:28px;
  border-radius:12px;
  max-width:1100px;
  margin:20px auto;
  background: var(--card-bg);
}

/* kiri (SVG) */
.notice-left{
  width:var(--left-w);
  height:var(--left-h);
  flex:0 0 var(--left-w);
  display:flex;
  align-items:center;
  justify-content:center;
  padding:10px;
  border-radius:10px;
}

/* hanya satu animasi untuk SVG: popup sekali dari bawah -> atas */
.svg-wrap{ width:100%; height:100%; display:flex; align-items:center; justify-content:center; position:relative; overflow:hidden; }
.svg-wrap svg{ width:100%; height:100%; display:block; opacity:0; transform: translateY(18px) scale(.98); transform-origin:center; transform-box:fill-box; }

/* kelas yg dipakai oleh JS untuk play once */
.svg-popup{ animation: svgPopOnce 560ms cubic-bezier(.2,.9,.2,1) forwards; }
@keyframes svgPopOnce{
  from{ transform: translateY(18px) scale(.98); opacity:0; }
  to{ transform: translateY(0) scale(1); opacity:1; }
}

/* kanan (melayang terus) */
.notice-right{
  flex:1 1 auto; min-width:0;
  /* floating hanya pada bagian kanan */
  animation: rightFloat 6.8s ease-in-out infinite;
  will-change: transform;
}

/* teks & tombol */
.text-wrap{ font-family:"Poppins","Montserrat",system-ui,Roboto,Arial; }
.title{
  font-family:"Montserrat","Poppins";
  font-weight:800;
  font-size:44px;
  margin:0 0 6px 0;
  /* untuk typing: kosongkan awal */
  overflow:hidden;
  white-space:nowrap;
  letter-spacing:0.5px;
  min-height:58px;
  position:relative;
}

/* cursor saat typing (tampil selama class .typing aktif) */
.title.typing::after{
  content: "";
  display:inline-block;
  width:2px;
  height:1.05em;
  background:var(--accent);
  position:absolute;
  right: -6px;
  top:8px;
  animation: blinkCursor 900ms steps(1) infinite;
}
@keyframes blinkCursor{ 50%{ opacity:0 } }

/* subtitle & body default hidden, nanti difade-in */
.subtitle, .body{
  font-size:17px;
  margin:0 0 12px 0;
  opacity:0;
  transform: translateY(8px);
  transition: opacity 420ms ease, transform 420ms cubic-bezier(.2,.9,.2,1);
}
.subtitle{ font-size:18px; font-weight:600; margin-bottom:10px; }

/* saat ready -> tampil */
.subtitle.enter, .body.enter{ opacity:1; transform:none; }

/* tombol */
.actions{ display:flex; gap:12px; align-items:center; }

.btn{
  border:0; padding:11px 16px; border-radius:10px; font-weight:700; cursor:pointer; font-size:20px;
  background:transparent; color:var(--accent); transition: transform .18s, box-shadow .18s;
  position:relative; overflow:visible;
}
.btn.primary{
  background: linear-gradient(90deg,#1b2e49,#2b4a7a);
  color:#fff;
  box-shadow: 0 6px 18px rgba(27,46,73,0.14);
  border: none;
}
.btn.ghost{
  border:1px dashed rgba(0,0,0,0.08);
  color:var(--accent);
  background:transparent;
}

/* efek hover heboh — lebih dramatis */
.btn:hover{
  transform: translateY(-8px) scale(1.04);
  box-shadow: 0 18px 40px rgba(27,46,73,0.16);
}

/* tambahan animasi 'heboh' singkat bila ingin dipicu via class */
@keyframes hebohPulse {
  0%{ transform: translateY(0) scale(1); }
  30%{ transform: translateY(-14px) scale(1.14); }
  70%{ transform: translateY(-6px) scale(1.06); }
  100%{ transform: translateY(0) scale(1); }
}
.btn.heboh { animation: hebohPulse 560ms cubic-bezier(.2,.9,.2,1); }

/* burst dots (dibuat oleh JS) */
.burst{ position:absolute; width:8px; height:8px; border-radius:50%; pointer-events:none; }

/* float animation hanya untuk kanan */
@keyframes rightFloat{
  0%{ transform: translateY(0); }
  25%{ transform: translateY(-8px); }
  50%{ transform: translateY(0); }
  75%{ transform: translateY(6px); }
  100%{ transform: translateY(0); }
}

/* responsive */
@media (max-width:880px){
  .notice-row{ flex-direction:column; gap:18px; padding:18px; max-width:720px; }
  .notice-left{ width:180px; height:370px; }
  .title{ font-size:34px; min-height:48px; }
}
</style>

<script>
(function(){
  const notice = document.getElementById('notice');
  const titleEl = document.querySelector('.title');
  const subtitle = document.querySelector('.subtitle');
  const body = document.querySelector('.body');
  const svg = document.querySelector('.svg-wrap svg');
  const signup = document.getElementById('signup');
  const back = document.getElementById('back');

  // 1) Play SVG popup ONCE (muncul dari bawah ke atas)
  if(svg){
    svg.classList.add('svg-popup');
    svg.addEventListener('animationend', ()=> {
      // biarkan final state (svgPopOnce forwards) tapi hapus kelas supaya tidak mengulang
      svg.classList.remove('svg-popup');
      svg.style.opacity = '1';
      svg.style.transform = 'none';
    }, { once:true });
  }

  // 2) Typing animation untuk title (JS letter-by-letter -> akurat untuk semua font)
  function typeText(el, fullText, speed=48){
    el.textContent = '';
    el.classList.add('typing');
    let i = 0;
    const tick = () => {
      if(i <= fullText.length - 1){
        el.textContent += fullText[i++];
        // atur posisi cursor (pseudo ::after posisi absolute right)
        // kita just leave cursor pseudo; absolute right mungkin perlu penyesuaian tergantung panjang
        setTimeout(tick, speed + Math.random()*18);
      } else {
        // selesai
        el.classList.remove('typing');
        // tampilkan subtitle & body
        subtitle.classList.add('enter');
        body.classList.add('enter');
      }
    };
    tick();
  }

  // mulai typing setelah sedikit delay agar kesan berurutan
  const initialDelay = 220; // ms
  const fullTitle = titleEl.dataset.full || 'Opps ...!';
  setTimeout(()=> typeText(titleEl, fullTitle, 38), initialDelay);

  // 3) Tombol: heboh saat hover (burst) & klik -> juga memberi pulse
  function createBurst(btn){
    const rect = btn.getBoundingClientRect();
    const btnRectWidth = rect.width;
    const btnRectHeight = rect.height;
    const colors = ['rgba(255,255,255,0.96)','rgba(255,255,255,0.72)','rgba(255,255,255,0.44)'];
    for(let i=0;i<7;i++){
      const dot = document.createElement('span');
      dot.className = 'burst';
      dot.style.background = colors[i%colors.length];
      dot.style.left = (btnRectWidth/2 - 4) + 'px';
      dot.style.top = (btnRectHeight/2 - 4) + 'px';
      dot.style.position = 'absolute';
      btn.appendChild(dot);
      const angle = (Math.PI*2) * (i/7) + (Math.random()*0.6 - 0.3);
      const dist = 18 + Math.random()*44;
      const tx = Math.cos(angle)*dist;
      const ty = Math.sin(angle)*dist - (6 + Math.random()*6);
      // gunakan Web Animations API bila tersedia
      if(dot.animate){
        dot.animate([
          { transform:'translate(0,0) scale(0.6)', opacity:1 },
          { transform:`translate(${tx}px, ${ty}px) scale(1)`, opacity:0.9 },
          { transform:`translate(${tx*1.6}px, ${ty*1.6}px) scale(0.18)`, opacity:0 }
        ], { duration: 540 + Math.random()*280, easing: 'cubic-bezier(.2,.9,.2,1)' }).onfinish = ()=> dot.remove();
      } else {
        setTimeout(()=> dot.remove(), 900);
      }
    }
  }

  // trigger burst on hover (mouseenter) and small pulse on click
[signup, back].forEach(btn => {
  if (!btn) return;

  btn.addEventListener('mouseenter', (e) => {
    const target = e.currentTarget; // simpan elemen-nya
    createBurst(target);

    target.classList.remove('heboh');
    void target.offsetWidth; // reset animation
    target.classList.add('heboh');

    // aman, karena pakai variabel lokal
    setTimeout(() => {
      if (target) target.classList.remove('heboh');
    }, 700);
  });

  btn.addEventListener('click', (e) => {
    const target = e.currentTarget;
    if (!target) return;
    target.classList.add('heboh');
    setTimeout(() => {
      if (target) target.classList.remove('heboh');
    }, 700);
  });
});


  // safety: pastikan svg tidak mendapat transform inline atau animasi lain
  if(svg) svg.style.willChange = 'opacity, transform';

})();
</script>